const now = new Date();
const run_id = `run_${now.toISOString().slice(0,10)}_${now.getTime()}`;
const started_at = now.toISOString();
const fromMs = now.getTime() - 72*3600*1000;
return [{ json: { run_id, started_at, window_from: new Date(fromMs).toISOString(), window_to: now.toISOString() } }];

// Filter enabled sources; coerce numeric trust_score.
const items = $input.all().map(i => i.json).filter(r => String(r.enabled||'').toLowerCase() === 'true' && r.url);
return items.map(s => ({ json: {
  source_id: s.source_id || '',
  name: s.name || '',
  url: s.url,
  type: String(s.type||'rss').toLowerCase(),
  tier: s.tier || 'tier2',
  topic_scope: s.topic_scope || '',
  trust_score: typeof s.trust_score === 'number' ? s.trust_score : parseFloat(s.trust_score || '0.5'),
  notes: s.notes || ''
}}));

// Normalize RSS items + apply date window early to keep memory low.
const run = $('Init Run').first().json;
const windowFrom = new Date(run.window_from).getTime();
const windowTo = new Date(run.window_to).getTime();
const out = [];
for (const it of $input.all()) {
  const r = it.json;
  const ms = r.isoDate ? new Date(r.isoDate).getTime() : (r.pubDate ? new Date(r.pubDate).getTime() : (r.published ? new Date(r.published).getTime() : null));
  if (ms != null && (ms < windowFrom || ms > windowTo)) continue;
  out.push({
    title: (r.title || '').slice(0, 280),
    url: r.link || r.url || '',
    summary: (r.contentSnippet || r.description || r.content || '').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').slice(0, 400),
    published_at: r.isoDate || r.pubDate || r.published || null,
    raw_type: 'rss'
  });
}
return out.map(o => ({ json: o }));

// Light HTML anchor extraction. Cap per-page output and trim heavy bodies.
const out = [];
for (const it of $input.all()) {
  const body = String(it.json.data || it.json.body || it.json.response || '').slice(0, 200000);
  const anchorRe = /<a[^>]+href="([^"]+)"[^>]*>([\s\S]*?)<\/a>/gi;
  let m, count=0;
  while ((m = anchorRe.exec(body)) !== null && count < 25) {
    const href = m[1];
    const text = m[2].replace(/<[^>]+>/g,'').replace(/\s+/g,' ').trim();
    if (text && text.length > 20 && text.length < 220 && /^https?:\/\//.test(href)) {
      out.push({ title: text.slice(0,280), url: href, summary: '', published_at: null, raw_type: 'html' });
      count++;
    }
  }
}
return out.map(o => ({ json: o }));

// Dedupe + window filter + source enrichment (by URL domain).
const run = $('Init Run').first().json;
const windowFrom = new Date(run.window_from).getTime();
const windowTo = new Date(run.window_to).getTime();
function domain(u){ try { return new URL(u).hostname.replace(/^www\./,'').toLowerCase(); } catch(e){ return ''; } }
function canonical(url){ if(!url) return ''; try { const u=new URL(url); u.hash=''; const drop=new Set(['utm_source','utm_medium','utm_campaign','utm_term','utm_content','gclid','fbclid','ref','ref_src']); const p=[...u.searchParams.entries()].filter(([k])=>!drop.has(k.toLowerCase())); u.search=new URLSearchParams(p).toString(); return u.toString().replace(/\/$/,'').toLowerCase(); } catch(e){ return String(url).toLowerCase(); } }
function normTitle(t){ return String(t||'').toLowerCase().replace(/[^a-z0-9 ]+/g,' ').replace(/\s+/g,' ').trim(); }
// Build source map by domain
const sources = $('Filter Enabled Sources').all().map(i=>i.json);
const byDomain = {};
for (const s of sources){ const d = domain(s.url); if (d && !byDomain[d]) byDomain[d] = s; }
function enrich(r){
  const src = byDomain[domain(r.url)] || {};
  return {
    ...r,
    source_name: r.source_name || src.name || '',
    source_tier: r.source_tier || src.tier || '',
    source_trust: (typeof r.source_trust==='number' ? r.source_trust : (typeof src.trust_score==='number' ? src.trust_score : 0.4))
  };
}
const raw = $input.all().map(i=>enrich(i.json)).filter(x=>x && (x.title||x.url));
const map = new Map();
let rawCount=0, dateKept=0;
for (const r of raw){
  rawCount++;
  const ms = r.published_at ? new Date(r.published_at).getTime() : null;
  const inWin = ms==null ? true : (ms>=windowFrom && ms<=windowTo);
  if(!inWin) continue;
  dateKept++;
  const cu = canonical(r.url);
  const nt = normTitle(r.title);
  const key = cu || `t:${nt}`;
  const prev = map.get(key);
  if(!prev){ map.set(key,r); continue; }
  if (r.source_trust > prev.source_trust) map.set(key,r);
  else if (r.source_trust === prev.source_trust && (r.summary||'').length > (prev.summary||'').length) map.set(key,r);
}
// Rank preliminarily by source_trust + recency, cap to top 40 to keep payload safe.
const dedupedAll = Array.from(map.values())
  .sort((a,b) => (b.source_trust - a.source_trust) || ((new Date(b.published_at||0)) - (new Date(a.published_at||0))));
const deduped = dedupedAll.slice(0, 40).map((r,i)=>({
  item_id:`i_${run.run_id}_${i}`, title:r.title||'', url:r.url||'', canonical_url:canonical(r.url),
  source_name:r.source_name||'', source_tier:r.source_tier||'', source_trust:r.source_trust,
  published_at:r.published_at||null, summary:(r.summary||'').slice(0,400),
  raw_type:r.raw_type||'', primary_topic:''
}));
return [{ json: { run_id:run.run_id, started_at:run.started_at, window_from:run.window_from, window_to:run.window_to, raw_items_count:rawCount, dated_kept:dateKept, deduped_count:deduped.length, total_dedup_pool: dedupedAll.length, sources_seen: Object.keys(byDomain).length, items:deduped }}];

// Build batched OpenRouter scoring request. Cap at 25 items (already sorted
// by trust_score in Dedupe + Filter) to keep the LLM response within max_tokens.
const cfg = $('Config').first().json;
const data = $json;
const items = (data.items || []).slice(0, 25);
if (!items.length) return [{ json: { ...data, skip_llm: true, scored_items: [] } }];
const system = `Sei un analista senior di AI/business. Valuti news AI per un pubblico italiano di imprenditori, PMI e liberi professionisti. Obiettivo: identificare news con takeaway pratico per il business (posizionamento, lead gen futura). Fonti ufficiali (openai.com, anthropic.com, blog.google, ai.meta.com, huggingface.co, microsoft.com, nvidia.com, mistral.ai) vanno premiate sul source_authority. Output: SOLO JSON valido.`;
const criteria = `Scoring 0-10 (sii generoso quando c'è un takeaway chiaro per un imprenditore/PMI):\n- candidate_score: quanto merita almeno un'analisi (news concreta, nuovo tool/release, trend rilevante)\n- publishable_score: quanto è pronto per un pacchetto editoriale oggi (news forte + narrativa costruibile)\n- confidence: 0-1, grado di certezza sui fatti\n- primary_topic: tag breve\n- rationale: 1 frase in italiano\n\nPremia: release/prodotti/tool AI usabili in azienda, posizionamenti strategici delle big lab, numeri o dati concreti, implicazioni per mercato/lavoro. Penalizza SOLO: hype puro senza fatti, paper accademici senza risvolti business, minor patch notes, chiacchiere di settore.`;
const userPayload = {
  task:'score_items', criteria,
  required_output_schema:{ scores:[{ item_id:'string', candidate_score:'0-10', publishable_score:'0-10', confidence:'0-1', primary_topic:'string', rationale:'1 frase' }]},
  items: items.map(it=>({ item_id:it.item_id, title:it.title, url:it.url, source_name:it.source_name, source_tier:it.source_tier, published_at:it.published_at, summary:(it.summary||'').slice(0,500) }))
};
const body = { model: cfg.modelMain, temperature:0.1, max_tokens:5500, response_format:{type:'json_object'}, messages:[{role:'system',content:system},{role:'user',content:JSON.stringify(userPayload)}] };
return [{ json: { ...data, openrouter_body: body } }];

// Parse scores, apply thresholds, select mode.
const cfg = $('Config').first().json;
const dataNode = $('Dedupe + Filter').first().json;
const items = dataNode.items || [];
function parse(s){
  if (!s) return null;
  let t = String(s).trim();
  // strip markdown fences like ```json ... ``` or ``` ... ```
  const m = t.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (m) t = m[1].trim();
  try { return JSON.parse(t); } catch(e){}
  // fallback: find outermost {...}
  const a = t.indexOf('{'), b = t.lastIndexOf('}');
  if (a>=0 && b>a) { try { return JSON.parse(t.slice(a,b+1)); } catch(e){} }
  return null;
}
let parsed = null;
const resp = $json;
const choices = resp.choices || (resp.body && resp.body.choices);
if (choices && choices[0]) parsed = parse(choices[0].message?.content);
const scoresById = {};
if (parsed && Array.isArray(parsed.scores)) { for (const s of parsed.scores) scoresById[s.item_id]=s; }
const enriched = items.map(it=>{
  const s = scoresById[it.item_id] || {};
  return { ...it,
    candidate_score: typeof s.candidate_score==='number'?s.candidate_score:0,
    publishable_score: typeof s.publishable_score==='number'?s.publishable_score:0,
    confidence: typeof s.confidence==='number'?s.confidence:0,
    primary_topic: s.primary_topic||'',
    rationale: s.rationale||''
  };
});
const candMin = Number(cfg.candidateMin)||7;
const pubMin  = Number(cfg.publishableMin)||8;
const confMin = Number(cfg.confidenceMin)||0.75;
const publishable = enriched.filter(x=>x.candidate_score>=candMin && x.publishable_score>=pubMin && x.confidence>=confMin).sort((a,b)=>(b.publishable_score-a.publishable_score)||(b.confidence-a.confidence));
const candidates  = enriched.filter(x=>x.candidate_score>=candMin && !publishable.includes(x)).sort((a,b)=>b.candidate_score-a.candidate_score);
let mode;
if (!enriched.length) mode='HARD_STOP';
else if (publishable.length>=3) mode='FULL_NEWS';
else if (publishable.length>=1) mode='HYBRID';
else if (candidates.length>=2) mode='MONITOR_ONLY';
else mode='FALLBACK';
const selected = publishable.slice(0,3);
const backup = candidates.slice(0,2);
const shortlist = [...selected, ...candidates.slice(0, Math.max(0,5-selected.length))].slice(0,5).map(x=>({ title:x.title, reason:x.rationale || `score ${x.publishable_score}` }));
return [{ json: {
  run_id: dataNode.run_id, started_at: dataNode.started_at, mode, enriched,
  selected_items: selected, backup_items: backup, shortlist,
  meta: { sources_total:0, sources_failed:0, raw_items_count:dataNode.raw_items_count, deduped_count:dataNode.deduped_count, selected_count:selected.length }
}}];

// Build single-item envelope for downstream WF2 + WF3.
const intel = $('Parse Scores + Select Mode').first().json;
const fbItems = $input.all().map(i=>i.json).filter(r=> String(r.enabled||'').toLowerCase()==='true');
const rank = { high:0, medium:1, low:2 };
fbItems.sort((a,b) => (rank[a.priority]??1) - (rank[b.priority]??1));
return [{ json: {
  run_id: intel.run_id,
  started_at: intel.started_at,
  mode: intel.mode,
  selected_items: intel.selected_items,
  backup_items: intel.backup_items,
  fallback_items: fbItems.slice(0,3),
  shortlist: intel.shortlist,
  meta: intel.meta,
  note: ''
}}];

// Emit one item per enriched ranked row for the Append node.
const intel = $('Parse Scores + Select Mode').first().json;
const selectedIds = new Set((intel.selected_items||[]).map(s=>s.item_id));
const rows = (intel.enriched||[]).map(x => ({
  run_id: intel.run_id,
  item_id: x.item_id,
  title: x.title,
  url: x.url,
  source_name: x.source_name || '',
  published_at: x.published_at || '',
  primary_topic: x.primary_topic || '',
  candidate_score: x.candidate_score,
  publishable_score: x.publishable_score,
  confidence: x.confidence,
  selected_yes_no: selectedIds.has(x.item_id) ? 'yes' : 'no',
  selection_reason: x.rationale || ''
}));
return rows.map(r => ({ json: r }));
